	// アンカーのIDの冒頭に「http://～」があればWebサイトを開く。
	if RE_MATCH(_id, 'http://.+') {
		_url = AYATEMPLATE.EscapeText(_id)
		"\C\j[%(_url)] \e"
	// それ以外はIDと同じ名前のイベントへジャンプ
	} elseif ISFUNC(_id) {
		EVAL(_id)
	}
}

OnAnchorSelectEx
{
	_id = reference[1]
	// アンカーのIDの冒頭に「http://～」があればWebサイトを開く。
	if RE_MATCH(_id, 'http://.+') {
		_url = AYATEMPLATE.EscapeText(_id)
		"\C\j[%(_url)] \e"
	// それ以外はIDと同じ名前のイベントへジャンプ
	} elseif ISFUNC(_id) {
