{ 
	if ARRAYSIZE(REQ.ARGS) < 1 {
		LOGGING("Sort: 引数が不足しています")
		-1
		return
	} 
	arX = SPLIT(REQ.ARGS[0],CHR(0x01)) 
	_x = quicksort(0,ARRAYSIZE(arX)-1) 
	_s = ""
	for _i = 0; _i < ARRAYSIZE(arX); _i++ {
		if (_i > 0) { _s = _s + CHR(0x01) }
		_s = _s + arX[_i]
	}
	RES.RESULT =_s
	ERASEVAR("arX")
}

